var userConnection = Get<UserConnection>("UserConnection");
Guid lineDetailId = Get<Guid>("LineDetailId");
Guid submissionId = Get<Guid>("SubmissionId");
string serialNumber = Get<string>("SerialNumber");
string validationType = Get<string>("ValidationType");

LineDetail lineDetail = new LineDetail(UserConnection);
var lines = new List<LineDetail>();
var lineResult = new List<LineResult>();

try {
    if(lineDetailId != Guid.Empty && submissionId == Guid.Empty && string.IsNullOrEmpty(serialNumber)) {
        lineDetail = new LineDetail(UserConnection, lineDetailId);
        lines.Add(lineDetail);
    } else if(lineDetailId == Guid.Empty && submissionId != Guid.Empty && string.IsNullOrEmpty(serialNumber)) {
        lines = lineDetail.GetLines(submissionId);
    } else if(lineDetailId == Guid.Empty && submissionId == Guid.Empty && !string.IsNullOrEmpty(serialNumber)) {
        lines = lineDetail.GetLines(serialNumber);
    } else {
    	throw new Exception("Line detail / Submission / Serial Number is required");
    }

    if(validationType == "All") {
        lineResult.AddRange(lineDetail.IsValid(lines));
    } else if(validationType == "Line") {
        lineResult.AddRange(lineDetail.IsLineMandatoryValid(lines));
    } else if(validationType == "Offer") {
        lineResult.AddRange(lineDetail.IsOfferingMandatoryValid(lines));
    } else {
        throw new Exception("Validation type is not valid");
    }

} catch(Exception e) {
    Set("Message", e.Message);
}

var result = lineResult.Count > 0 ? 
    JsonConvert.SerializeObject(lineResult.Select(item => item.Result).ToList(), Formatting.Indented) : 
    string.Empty;
Set("Result", result);

return true;
